const now = Date.now()
const ctx = query.context && typeof query.context === 'object' ? query.context : {}
const sid = query.session_id ?? ctx.session_id ?? null
const req = query.request_id ?? ctx.request_id ?? null
const pick = Array.isArray(query.pick) ? query.pick : []
const src = query.result ?? query.data ?? query.input ?? null
const val = pick.length && src && typeof src === 'object' && !Array.isArray(src)
  ? Object.fromEntries(pick.filter((key) => key in src).map((key) => [key, src[key]]))
  : src
const started = typeof ctx.timestamp === 'string' ? Date.parse(ctx.timestamp) : Number.NaN
const time = Number.isFinite(started) ? Math.max(0, now - started) : 0
const tools = Array.isArray(query.tools_used)
  ? Array.from(new Set(query.tools_used.filter(Boolean)))
  : []
const used = tools.length ? tools : ['code']
const memory = query.memory_references && typeof query.memory_references === 'object'
  ? query.memory_references
  : undefined

if (query.status === 'error' || query.error) {
  const err = query.error && typeof query.error === 'object' ? query.error : {}
  return JSON.stringify({
    status: 'error',
    session_id: sid,
    request_id: req,
    error: {
      type: err.type ?? query.type ?? 'workflow_error',
      message: err.message ?? query.message ?? 'Workflow execution failed',
      retries: Number.isFinite(err.retries) ? err.retries : Number.isFinite(query.retries) ? query.retries : 0,
      last_attempt_url: err.last_attempt_url ?? query.url ?? query.last_attempt_url ?? null,
    },
    fallback_response: query.fallback_response ?? {
      available: true,
      message: 'Unable to fetch data from external source',
    },
    tools_used: used,
    execution_time_ms: time,
  })
}

return JSON.stringify({
  status: query.status ?? 'success',
  session_id: sid,
  request_id: req,
  result: val,
  ...(memory ? { memory_references: memory } : {}),
  tools_used: used,
  execution_time_ms: time,
})

